-- Personal channels for admin (id=1) -- Channel 1: Active, production use INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Backend Errors', 'Production error tracking for backend services. Monitors API failures, database issues, and service exceptions.', 1, NULL, 'ACTIVE', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '45 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '2 hours' );
-- Channel 2: Active, monitoring INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Frontend Analytics', 'User behavior and performance metrics from the web application.', 1, NULL, 'ACTIVE', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '1 day' );
-- Channel 3: Active, CI/CD INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Deployment Events', 'Tracks deployments, rollbacks, and infrastructure changes across all environments.', 1, NULL, 'ACTIVE', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '60 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '30 minutes' );
-- Channel 4: Paused, seasonal use INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Marketing Campaigns', 'Event tracking for seasonal marketing campaigns. Paused between campaigns.', 1, NULL, 'PAUSED', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '90 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '15 days' );
-- Channel 5: Active, security INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Security Alerts', 'Critical security events including failed login attempts, suspicious activity, and access violations.', 1, NULL, 'ACTIVE', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '120 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '5 minutes' );
-- Channel 6: Active, no description INSERT INTO channel (name, description, user_id, organization_id, status, created_at, updated_at) VALUES ( 'Test Channel', NULL, 1, NULL, 'ACTIVE', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '5 days', (CURRENT_TIMESTAMP AT TIME ZONE 'UTC') - INTERVAL '5 days' );

